import{_ as t,o as s,i as o,a9 as i}from"./chunks/framework.DuwpaNh0.js";const a="/modules/devdocs/assets/step1.DoElSlys.png",r="/modules/devdocs/assets/step2.B6tEhvPt.png",m=JSON.parse('{"title":"Using the Development Server","description":"","frontmatter":{},"headers":[],"relativePath":"modules/4-testing/2-devserver/2-devserver.md","filePath":"modules/4-testing/2-devserver/2-devserver.md","lastUpdated":1784558893000}'),d={name:"modules/4-testing/2-devserver/2-devserver.md"};function n(l,e,h,p,c,u){return s(),o("div",null,e[0]||(e[0]=[i('<h1 id="using-the-development-server" tabindex="-1">Using the Development Server <a class="header-anchor" href="#using-the-development-server" aria-label="Permalink to &quot;Using the Development Server&quot;">​</a></h1><p>The Development Server (or devserver, for short) is a lightweight version of the frontend that provides developers with a copy of the Source Academy playground so that they can run their bundle code and see the actual graphic interface of their tabs.</p><p>There are many features absent from the devserver (such as assessments). If you need to test your bundles and tabs with those features, you will need to test with the frontend instead.</p><p>The REPL provided by the devserver will display output as seen by cadets. Detailed error information can be found in the browser console (as well as any <code>console.log</code> calls made by your code).</p><h2 id="running-the-dev-server" tabindex="-1">Running the Dev Server <a class="header-anchor" href="#running-the-dev-server" aria-label="Permalink to &quot;Running the Dev Server&quot;">​</a></h2><p>If you used a focused install, you may have to run this command first:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> workspaces</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> focus</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @sourceacademy/modules-devserver</span></span></code></pre></div><p>Then to start the devserver, simply run the following command from the <strong>root</strong> of the repository:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devserver</span></span></code></pre></div><div class="note custom-block github-alert"><p class="custom-block-title">Pre-Compilation</p><p></p><p>Because the dev server relies on Vite which needs to pre-bundle its dependencies, you will need to have compiled any tabs you&#39;re intending to test using the steps listed <a href="./../../3-tabs/4-compiling.html">here</a> before starting the dev server.</p><p>You should also ensure that modules manifest has been built.</p></div><p>The dev server can then be viewed from the web browser.</p><h2 id="hot-reload-mode" tabindex="-1">Hot-Reload Mode <a class="header-anchor" href="#hot-reload-mode" aria-label="Permalink to &quot;Hot-Reload Mode&quot;">​</a></h2><p>By default, the dev server is in hot reload mode. This means the dev server can detect changes as they are being made and automatically reload the displayed tab without requiring a refresh of the page or for the user to rerun code.</p><div class="important custom-block github-alert"><p class="custom-block-title">Working with Bundles in Hot-Reload Mode</p><p></p><p>Tabs depend on bundles in 1 of 2 ways:</p><ul><li>Javascript dependency (i.e if you import from <code>@sourceacademy/bundle-curve</code>)</li><li>Source dependency (i.e. if the bundle was imported and evaluated through <code>js-slang</code>)</li></ul><p>Vite can detect changes for Javascript dependencies, but if your tab imports your bundle through <code>js-slang</code> as well then you will need to rebuild your bundle for the new version to be loaded by <code>js-slang</code>.</p></div><h2 id="compiled-mode" tabindex="-1">Compiled Mode <a class="header-anchor" href="#compiled-mode" aria-label="Permalink to &quot;Compiled Mode&quot;">​</a></h2><p>In this mode, the dev server can only detect the changes you&#39;ve made <strong>after</strong> you&#39;ve compiled your tab or bundle. Should you wish to test the compiled versions instead of the raw Typescript source, you can switch the dev server to compiled mode by following the steps below:</p><ol><li><p>Click on the settings button: <img src="'+a+'" alt=""></p></li><li><p>Switch to compiled mode <img src="'+r+'" alt=""></p></li></ol><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p></p><p>When switching between modes, you will need to re-run code for the different version of the tab/bundle to be loaded.</p></div><p>If need be, you can use the the textbox to customize which server to load modules from. You may have to rerun your code after switching this setting for the server to load the asset you&#39;ve selected.</p><div class="important custom-block github-alert"><p class="custom-block-title">Working with Bundles in Compiled Mode</p><p></p><p>The limitations for hot-reload mode also apply to compiled mode, but you must recompile and rebuild your bundle before rebuilding your tab, following which, you can then rerun your code to see the changes in effect.</p></div>',20)]))}const b=t(d,[["render",n]]);export{m as __pageData,b as default};
